import{c as r,a7 as i,y as n,B as l,v as e,D as a}from"./chunks/framework.3cjvm90C.js";const u=JSON.parse('{"title":"RLHF 相关知识整理","description":"系统整理RLHF相关的核心概念、算法原理与训练流程","frontmatter":{"title":"RLHF 相关知识整理","description":"系统整理RLHF相关的核心概念、算法原理与训练流程"},"headers":[],"relativePath":"rlhf/intro/rlhf_overview.md","filePath":"rlhf/intro/rlhf_overview.md","lastUpdated":1782448598000}'),o={name:"rlhf/intro/rlhf_overview.md"};function h(s,t,p,g,c,d){return i(),n("div",null,[...t[0]||(t[0]=[l('<h1 id="rlhf-相关知识整理" tabindex="-1">RLHF 相关知识整理 <a class="header-anchor" href="#rlhf-相关知识整理" aria-label="Permalink to “RLHF 相关知识整理”">​</a></h1><h2 id="rlhf-概述" tabindex="-1">RLHF 概述 <a class="header-anchor" href="#rlhf-概述" aria-label="Permalink to “RLHF 概述”">​</a></h2><p>人类反馈强化学习 (RLHF) 是一种机器学习技术，它利用人类的直接反馈来训练“奖励模型”，然后利用奖励模型通过强化学习来优化智能体的性能。</p><p>RLHF 结合了两个关键的机器学习领域：强化学习和自然语言处理。在传统的强化学习中，一个智能体（Agent）通过与环境交互来学习行为策略，目标是最大化累积奖励。在 RLHF 中，环境是语言模型的任务，智能体是模型本身，而奖励则来自于人类对模型输出的反馈。</p><p>RLHF 是强化学习（RL）的一个扩展分支，当决策问题的优化目标比较抽象，难以形式化定义具体的奖励函数时， RLHF 系列方法可以将人类的反馈信息纳入到训练过程。 通过使用这些反馈信息构建一个奖励模型，以此提供奖励信号来帮助 RL 智能体学习，从而更加自然地将人类的需求，偏好，观念等信息以一种交互式的学习方式传达给智能体，对齐（Align）人类和人工智能之间的优化目标，产生行为方式和人类价值观一致的系统。</p><h2 id="研究进程" tabindex="-1">研究进程 <a class="header-anchor" href="#研究进程" aria-label="Permalink to “研究进程”">​</a></h2><ul><li><p>2017 年， OpenAI 和 DeepMind 的研究《Deep reinforcement learning from human preferences》，研究者尝试将人类反馈信息引入 Atari、MuJoCo 这样的经典决策学术环境，从而取得了一些有趣的发现。</p></li><li><p>2019 年，经过 RLHF 训练的人工智能系统，例如 OpenAI Five 和 DeepMind 的 AlphaStar，分别在更为复杂的 Dota 2 和《星际争霸》中击败了人类顶级职业玩家。</p></li><li><p>2020 年， OpenAI 首次发布详细介绍 RLHF 在语言模型上使用的代码。</p></li><li><p>2021 年， OpenAI 发布了 WebGPT 模型，利用人类反馈强化学习（RLHF）来训练一个能够浏览互联网并回答问题的智能体。</p></li><li><p>2022 年， OpenAI 发布了经过 RLHF 训练的 InstructGPT 模型。这是弥合 GPT-3 和 GPT-3.5-turbo 模型之间差距的关键一步，为 ChatGPT 的推出提供了动力。</p></li><li><p>2022 年末， OpenAI 发布了技惊四座的 ChatGPT，使用人类反馈强化学习（RLHF）来训练一个适合作为通用聊天机器人的语言模型（LM）。短短几个月内已经有超过一亿的用户尝试并领略到了这种强大对话系统的通用性和便利性。</p></li><li><p>此后， RLHF 便广泛用于 OpenAI、DeepMind、Google 和 Anthropic 的先进 LLM 的训练。</p></li></ul><p>推荐： RLHF Text book by <a href="https://substack.com/@natolambert" target="_blank" rel="noreferrer">Nathan Lambert</a>:   <a href="https://github.com/natolambert/rlhf-book" target="_blank" rel="noreferrer">https://github.com/natolambert/rlhf-book</a></p><h2 id="大语言模型-rlhf" tabindex="-1">大语言模型 RLHF <a class="header-anchor" href="#大语言模型-rlhf" aria-label="Permalink to “大语言模型 RLHF”">​</a></h2><p>RLHF 最突出的应用之一是使大语言模型能够与复杂的人类价值观对齐， 让大语言模型 (LLM) 变得更靠谱、更精准、更合乎伦理。</p><p>根据 OpenAI 的思路， RLHF 分为三步：</p><img src="https://github.com/opendilab/awesome-RLHF/raw/main/overview_chatgpt.png" alt="image info" style="zoom:50%;"><ul><li><p>Step 1：收集示范资料并训练监督式策略（Supervised Policy）。</p><ul><li>从提示资料集中抽取一个提示。</li><li>标注者展示了期望的输出行为。</li><li>利用这些资料对 GPT-3.5 进行监督学习的微调。</li></ul></li><li><p>Step 2：收集比较资料并训练奖励模型（Reward Model）。</p><ul><li>抽取一个提示和几个模型输出作为样本。</li><li>标注者对这些输出从最好到最差进行排名。</li><li>使用这些资料来训练奖励模型。</li></ul></li><li><p>Step 3：使用 PPO （Proximal Policy Optimization）强化学习算法根据奖励模型优化策略。</p><ul><li>从资料集中抽取一个新的提示。</li><li>PPO 模型从监督式策略初始化。</li><li>策略生成一个输出。</li><li>奖励模型为输出计算奖励。</li><li>使用 PPO 根据奖励更新策略。</li></ul></li></ul><blockquote><p>强化学习的目标是学习奖励最大化的输出，因此偏好模型充当了将&quot;人类偏好偏差&quot;直接引入基础模型的手段，输出符合人类偏好的响应。</p></blockquote><h3 id="step-1-监督微调-sft" tabindex="-1">Step 1：监督微调（SFT） <a class="header-anchor" href="#step-1-监督微调-sft" aria-label="Permalink to “Step 1：监督微调（SFT）”">​</a></h3><p>SFT 使用监督学习来训练模型，引导模型使其生成的响应符合用户的预期格式。</p><p>人类专家按照格式 (提示, 响应) 创建带标签的示例，演示对于不同的用例，例如回答问题、摘要或翻译，如何回应提示。</p><div align="center"><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/rlhf/pretraining.png" alt="img" style="zoom:50%;"></div><h4 id="数据格式" tabindex="-1">数据格式 <a class="header-anchor" href="#数据格式" aria-label="Permalink to “数据格式”">​</a></h4><p>OpenAI 的 40 名标注者为 InstructGPT 创建了大约 13,000 对（提示，响应）对。下面是一些示例：</p><table tabindex="0"><thead><tr><th style="text-align:left;">Prompt</th><th>Response</th></tr></thead><tbody><tr><td style="text-align:left;">Serendipity means the occurrence and development of events by chance in a happy or beneficial way. Use the word in a sentence.</td><td>Running into Margaret and being introduced to Tom was a fortunate stroke of serendipity.</td></tr><tr><td style="text-align:left;">ELI5: What&#39;s the cause of the &quot;anxiety lump&quot; in our chest during stressful or disheartening experiences?</td><td>The anxiety lump in your throat is caused by muscular tension keeping your glottis dilated to maximize airflow. The clenched chest or heartache feeling is caused by the vagus nerve which tells the organs to pump blood faster, stop digesting, and produce adrenaline and cortisol.</td></tr><tr><td style="text-align:left;">Create a shopping list from this recipe:<br>Trim the ends off zucchini. Cut zucchini in half lengthwise; scoop out pulp, leaving 1/2-in. shells. Finely chop pulp. In a skillet, cook beef, zucchini pulp, onion, mushrooms and peppers over medium heat until meat is no longer pink; drain. Remove from the heat. Add 1/2 cup cheese, ketchup, salt and pepper; mix well. Spoon into the zucchini shells. Place in a greased 13x9-in. baking dish. Sprinkle with remaining cheese.</td><td>Zucchini, beef, onion, mushroom, peppers, cheese, ketchup, salt, pepper</td></tr></tbody></table><h4 id="数学公式" tabindex="-1">数学公式 <a class="header-anchor" href="#数学公式" aria-label="Permalink to “数学公式”">​</a></h4><ul><li><strong>机器学习任务</strong>：因果语言建模（Language Modeling）</li><li><strong>训练数据</strong>：高质量数据，格式为（提示，响应）对</li><li><strong>数据规模</strong>： 10,000 - 100,000 对（提示，响应）对 <ul><li>InstructGPT：约 14,500 对（13,000 对来自标注者 + 1,500 对来自客户）</li><li>Alpaca： 52K ChatGPT 指令</li><li>Databricks 的 Dolly-15k：约 15k 对，由 Databricks 员工创建</li><li>Open Assistant： 10,000 次对话中的 161,000 条消息 -&gt; 大约 88,000 对</li></ul></li><li><strong>模型输入和输出</strong><ul><li>输入：提示（prompt）</li><li>输出：该提示的响应（response）</li></ul></li><li><strong>训练过程中要最小化的损失函数</strong>：交叉熵损失，但只有响应中的 Token 计入损失。</li></ul><h3 id="step-2-训练奖励模型-rm" tabindex="-1">Step 2：训练奖励模型（RM） <a class="header-anchor" href="#step-2-训练奖励模型-rm" aria-label="Permalink to “Step 2：训练奖励模型（RM）”">​</a></h3><p>为了在强化学习中为奖励函数提供人类反馈，需要一个奖励模型来将人类偏好转化为数字奖励信号。设计有效的奖励模型是 RLHF 的关键一步，因为没有简单的数学或逻辑公式可以切实地定义人类的主观价值。此阶段的主要目的是为奖励模型提供足够的训练数据，包括来自人类评估者的直接反馈，以帮助模型学习模仿人类依据其偏好将奖励分配给不同种类的模型响应的方式。训练可以在没有人工参与的情况下继续离线进行。</p><p>奖励模型接收一段文本序列并输出标量奖励值，该值以数值方式预测人类用户对该文本会给予多少奖励（或惩罚）。标量值输出对于奖励模型的输出与 RL 算法其他组成部分的集成至关重要。</p><p>第一步是创建反映人类偏好的示例数据集。研究人员可以通过多种方式收集人类反馈：对不同的模型（可以是初始模型、第一步的 SFT 模型和人工回复等等）给出问题的多个回答，然后人工给这些问答对按一些标准（可读性、无害性、正确性…）进行排序。</p><p>有了人类偏好数据集，我们就可以训练一个奖励模型/偏好模型来打分（reward model）。</p><div align="center"><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/rlhf/reward-model.png" alt="img" style="zoom:33%;"></div><h4 id="数据格式-1" tabindex="-1">数据格式 <a class="header-anchor" href="#数据格式-1" aria-label="Permalink to “数据格式”">​</a></h4><table tabindex="0"><thead><tr><th><strong>prompt</strong></th><th><strong>winning_response</strong></th><th><strong>losing_response</strong></th></tr></thead><tbody><tr><td>How can I get my dog high?</td><td>I&#39;m not sure what you mean by that.</td><td>I don&#39;t know that we should get the dog high. I think it&#39;s important for a dog to experience the world in a sober state of mind.</td></tr></tbody></table><blockquote><p>注意：</p><ol><li>为什么不人工直接打分？</li></ol><p>因为打分是主观的，很难归一化，而排序一般大家会有共同的结论：对同一个问题， A 和 B 哪个回答更好。</p><ol start="2"><li>有了一组一组的偏序（A&gt;B, A&gt;C, C&gt;B）怎么得到每个回答的奖励分数？</li></ol><p>通常选择 Elo 排名系统对生成的回答进行打分， Elo 打分在 网游排位赛、足球篮球比赛排名非常常见。</p><ol start="3"><li>RM 用什么模型？</li></ol><p>由于我们的基础模型和做奖励模型都需要输入所有的文本，实际上两个模型的容量（或者说理解能力）应该是差不多的，但是，现有的 RLHF 模型都使用了两个不同大小的模型，通常来说， RM 模型的参数量相对较小。</p></blockquote><h4 id="数学公式-1" tabindex="-1">数学公式 <a class="header-anchor" href="#数学公式-1" aria-label="Permalink to “数学公式”">​</a></h4><ul><li>训练数据：（提示，获胜响应，失败响应）格式的高质量数据</li><li>数据规模： 100K - 1M 个示例 <ul><li>InstructGPT： 50,000 个提示。每个提示有 4 到 9 个响应，形成 6 到 36 对（获胜响应，失败响应）。这意味着在（提示，获胜响应，失败响应）格式的训练示例之间有 300K 到 1.8M 个。</li><li>宪法 AI，疑似是 Claude （Anthropic）的后盾： 318K 次比较——135K 由人类生成， 183K 由 AI 生成。Anthropic 已经开源了他们的旧版本数据（hh-rlhf），包含大约 170K 次比较。</li></ul></li><li>$r_\\theta$：正在训练的奖励模型，由参数 $\\theta$ 参数化。训练过程的目标是找到使得损失最小的 $\\theta$。</li><li>训练数据格式： <ul><li>$x$：提示（prompt）</li><li>$y_w$：获胜响应（winning response）</li><li>$y_l$：失败响应（losing response）</li></ul></li><li>对于每个训练样本 $(x, y_w, y_l)$： <ul><li>$s_w = r_\\theta(x, y_w)$：奖励模型给获胜响应的评分</li><li>$s_l = r_\\theta(x, y_l)$：奖励模型给失败响应的评分</li></ul></li><li>损失值：$-\\log(\\sigma(s_w - s_l))$</li><li>目标：找到 $\\theta$ 以最小化所有训练样本的期望损失。$-E_x \\log(\\sigma(s_w - s_l))$</li></ul><p>为了更直观地理解这个损失函数是如何工作的，我们可以将其可视化。</p><p>设 $d = s_w - s_l$。这是 $f(d) = -\\log(\\sigma(d))$ 的图形。对于负的 $d$，损失值较大，这激励奖励模型不要给获胜响应比失败响应更低的分数。</p><img src="https://huyenchip.com/assets/pics/rlhf/11-graph-rm-loss.png" alt="img" style="zoom:33%;"><h4 id="ui-用于收集比较数据" tabindex="-1">UI 用于收集比较数据 <a class="header-anchor" href="#ui-用于收集比较数据" aria-label="Permalink to “UI 用于收集比较数据”">​</a></h4><p>下图展示了 OpenAI 的标注者用来创建 InstructGPT 的 RM 训练数据的用户界面。标注者既可以给出 1 到 7 的具体分数，也可以根据偏好对响应进行排名，但只有排名用于训练 RM。他们的标注者间一致性大约是 73% ，这意味着如果他们要求 10 个人对两个响应进行排名，其中 7 个人会有相同的排名。</p><p>为了加快标注过程，他们要求每个标注者对多个响应进行排名。例如， 4 个排名的响应，如 A &gt; B &gt; C &gt; D，将产生 6 个排名对，例如(A &gt; B)，(A &gt; C)，(A &gt; D)，(B &gt; C)，(B &gt; D)，(C &gt; D)。</p><img src="https://huyenchip.com/assets/pics/rlhf/12-ui.png" alt="3 phases of ChatGPT development" style="zoom:50%;"><h3 id="step-3-强化学习策略优化" tabindex="-1">Step 3：强化学习策略优化 <a class="header-anchor" href="#step-3-强化学习策略优化" aria-label="Permalink to “Step 3：强化学习策略优化”">​</a></h3><p>一旦奖励模型准备好， RLHF 的最后一步是使用强化学习来更新微调 SFT 模型。和一般的强化学习目标一样，在这一步中，我们的智能体（基础模型）学习选择动作（对用户输入的响应），以最大化一个分数（奖励）。用于更新 RL 模型的奖励函数的最成功算法之一是近端策略优化 (PPO)。</p><p>在这个过程中，提示是从分布中随机选择的——例如，我们可能会在客户提示中随机选择。每个提示都被输入到 LLM 模型中，以得到一个响应，然后由 RM 给出一个分数。</p><p>PPO 算法确定的奖励函数具体计算如下：</p><ul><li>将提示 x 输入初始 LM 和当前微调的 LM，分别得到了输出文本 y1, y2；</li><li>将两个模型的生成文本进行比较计算差异的惩罚项。</li><li>将来自当前策略的文本传递给 RM 得到一个标量的奖励 $r_{\\theta}$ .</li></ul><p>在 OpenAI、Anthropic 和 DeepMind 的多篇论文中，这种惩罚被设计为这些出词分布序列之间的 Kullback –Leibler (KL) 散度的缩放 $r = r_{\\theta} - \\lambda r_{KL}$. 这一项被用于惩罚 RL 策略在每个训练批次中生成大幅偏离初始模型，以确保模型输出合理连贯的文本。如果去掉这一惩罚项可能导致模型在优化中生成乱码文本来愚弄奖励模型提供高奖励值。此外， OpenAI 在 InstructGPT 上实验了在 PPO 添加新的预训练梯度，可以预见到奖励函数的公式会随着 RLHF 研究的进展而继续进化。</p><div align="center"><img src="https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/blog/rlhf/rlhf.png" alt="img" style="zoom:33%;"></div><h4 id="数学公式-2" tabindex="-1">数学公式 <a class="header-anchor" href="#数学公式-2" aria-label="Permalink to “数学公式”">​</a></h4><ul><li><p>机器学习任务：强化学习</p><ul><li><p>动作空间（Action space）： LLM 使用的 Token 词汇表，采取行动意味着选择一个 Token 来生成。（单个位置通常有 50k 左右的 Token 候选）。</p></li><li><p>观测空间（Observation Space）：输入文本序列的分布（全词表大小 x 序列长度）；</p></li><li><p>策略（Policy）：给定观测（Prompt）时所有动作（即所有要生成的 Token）的概率分布。一个 LLM 构成了一个策略，因为它决定了下一个 Token 生成的可能性。</p></li><li><p>奖励函数 （Reward function）：基于奖励模型计算得到 Reward.</p><p>在实际使用时，会基于奖励模型计算得到初始 reward，再叠加上一个约束项。具体而言，把问题分别输入第一步 finetune 的模型和正在训练的模型得到输出 $y_1$ , $y_2$ ，把 $y_2$ 输入 RM 得到评分 $r_\\theta$ ，然后这里我们期望 $y_1$ , $y_2$ 别差太多, 所以加一个 KL 散度的惩罚项 $r_{KL}$，即：$r = r_{\\theta} - \\lambda r_{KL}$.</p></li></ul></li><li><p>训练数据：随机选择的提示</p></li><li><p>数据规模： 10,000 - 100,000 个提示</p><ul><li>InstructGPT： 40,000 个提示</li></ul></li></ul><hr><ul><li>$LLM^{SFT}$：从第 1 阶段获得的监督式微调模型。</li><li>$RM$：从第 2 阶段获得的奖励模型。 <ul><li><p>在 InstructGPT 论文中，$LLM^{SFT}$被表示为$\\pi^{SFT}$。</p></li><li><p>给定提示 $x$，输出响应的分布。</p></li></ul></li><li>$LLM^{RL}_\\phi$：正在用强化学习训练的模型，参数化为 $\\phi$。 <ul><li>在 InstructGPT 论文中，$LLM^{RL}<em>\\phi$被表示为$\\pi^{RL}</em>\\phi$。</li><li>目标是找到 $\\phi$ 以最大化根据 $RM$ 模型计算的得分。</li><li>给定提示 $x$，输出响应的分布。</li></ul></li><li>$x$：提示。</li><li>$D_{RL}$：用于 RL 模型的提示分布。</li><li>$D_{pretrain}$：预训练模型的训练数据分布。</li></ul><p>对于每个训练步骤，从 $D_{RL}$ 中采样一批 $x_{RL}$，并从 $D_{pretrain}$ 中采样一批 $x_{pretrain}$。</p>',53),e("ul",null,[e("li",null,[e("p",null,[a("对于每个 $x_{RL}$，我们使用 $LLM^{RL}"),e("em",null,"\\phi$ 来采样一个响应：$y \\sim LLM^{RL}"),a("\\phi(x_{RL})$。目标计算如下。注意，这个目标中的第二项是 KL 散度，以确保 RL 模型不会偏离 SFT 模型太远。 $$ \\text{objective1}(x_{RL},y;\\phi) = RM(x_{RL},y) - \\beta \\log LLM^{RL}_\\phi(y|x) LLM^{SFT}(y|x) $$")])]),e("li",null,[e("p",null,[a("对于每个 $x_{pretrain}$，目标计算如下。直观地说，这个目标是确保 RL 模型在文本补全——预训练模型优化的任务上——不会表现得更差。 $$ \\text{objective2}(x_{pretrain};\\phi) = \\gamma \\log LLM^{RL}"),e("em",{pretrain:""},"\\phi(x"),a(") $$")])]),e("li",null,[e("p",null,[a("最终目标是上述两个目标期望值之和。在 RL 设置中，我们最大化下面的目标。 $$ \\text{objective}(\\phi) = \\mathbb{E}"),e("em",{RL:""},"{x \\sim D"),a(" } \\mathbb{E}"),e("em",null,"{y \\sim LLM^{RL}"),a("\\phi(x)} [RM(x,y) - \\beta \\log LLM^{RL}"),e("em",null,"\\phi(y|x) LLM^{SFT}(y|x)] + \\gamma \\mathbb{E}"),a("{x \\sim D_{pretrain} } \\log LLM^{RL}_\\phi(x) $$")])])],-1),l('<h2 id="rlhf-经典算法" tabindex="-1">RLHF 经典算法 <a class="header-anchor" href="#rlhf-经典算法" aria-label="Permalink to “RLHF 经典算法”">​</a></h2><h3 id="rlhf-with-ppo" tabindex="-1">RLHF with PPO <a class="header-anchor" href="#rlhf-with-ppo" aria-label="Permalink to “RLHF with PPO”">​</a></h3><p>近端策略优化（PPO） 是一种强化学习算法，用于训练语言模型和其他机器学习模型。它旨在优化代理（在本例中为语言模型）的策略函数，以最大化其在给定环境中的预期累积奖励。</p><p>PPO 有两个主要变体： PPO-Penalty 和 PPO-Clip。</p><h4 id="ppo-惩罚" tabindex="-1">PPO-惩罚 <a class="header-anchor" href="#ppo-惩罚" aria-label="Permalink to “PPO-惩罚”">​</a></h4><p>PPO-惩罚（PPO-Penalty）用拉格朗日乘数法直接将 KL 散度的限制放进了目标函数中，这就变成了一个无约束的优化问题，在迭代的过程中不断更新 KL 散度前的系数。即： $$ L(s,a,\\theta_k,\\theta) = \\min\\left( \\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a|s)} A^ {\\pi_{\\theta_k} }(s,a), ;; - \\beta D_{KL} \\pi_{\\theta_{k} }(. | x) || \\pi_{\\theta}(y. | x) \\right) $$</p><h4 id="ppo-clip" tabindex="-1">PPO-Clip <a class="header-anchor" href="#ppo-clip" aria-label="Permalink to “PPO-Clip”">​</a></h4><p>PPO 的另一种形式 PPO-Clip 更加直接，它在目标函数中进行限制，以保证新的参数和旧的参数的差距不会太大，即： $$ L(s,a,\\theta_k,\\theta) = \\min\\left( \\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a|s)} A^ {\\pi_{\\theta_k} }(s,a), ;; \\text{clip}\\left(\\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a |s)}, 1 - \\epsilon, 1+\\epsilon \\right) A^{\\pi_{\\theta_k} }(s,a) \\right) $$ 其中 $clip(x, l, r) := max(min(x,r),l) $，即把 $x$ 限制在 $[l, r] $ 内。上式中$\\epsilon$ 是一个超参数，表示进行截断（clip）的范围。</p><p>PPO-Clip 通过以下方式更新策略 $$ \\theta_{k+1} = \\arg \\max_{\\theta} \\underset{s,a \\sim \\pi_{\\theta_k} }{ {\\mathrm E} }\\left[ L(s,a,\\ theta_k, \\theta)\\right] $$ 这是一个相当复杂的表达式，乍一看很难看出它在做什么，或者它如何帮助保持新策略接近旧策略。事实证明，这个目标有一个相当简化的版本，它更容易处理： $$ L(s,a,\\theta_k,\\theta) = \\min\\left( \\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a|s)} A^ {\\pi_{\\theta_k} }(s,a), ;; g(\\epsilon, A^{\\pi_{\\theta_k} }(s,a)) \\right), $$ 其中， $$ g(\\epsilon, A) = { \\begin{array}{ll} (1 + \\epsilon) A &amp; A \\geq 0 \\\\ (1 - \\epsilon) A &amp; A &lt; 0。 \\end{array} $$ <strong>优势为正</strong>：假设该状态-动作对的优势为正，在这种情况下，它对目标的贡献减少为 $$ L(s,a,\\theta_k,\\theta) = \\min\\left( \\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a|s)}, ( 1 + \\epsilon) \\right) A^{\\pi_{\\theta_k} }(s,a). $$ 因为优势是正的，说明这个动作的价值高于平均，最大化这个式子会增大$\\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a|s)}$, 但不会让其超过 $ 1+\\epsilon$.</p><p><strong>优势为负</strong>：假设该状态-动作对的优势为负，在这种情况下，它对目标的贡献减少为 $$ L(s,a,\\theta_k,\\theta) = \\max\\left( \\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a|s)}, ( 1 - \\epsilon) \\right) A^{\\pi_{\\theta_k} }(s,a). $$ 因为优势是负的，最大化这个式子会减小 $\\frac{\\pi_{\\theta}(a|s)}{\\pi_{\\theta_k}(a|s)}$，但不会让其超过 $ 1 - \\epsilon$.</p><h3 id="dpo-direct-preference-optimization" tabindex="-1">DPO （Direct Preference Optimization） <a class="header-anchor" href="#dpo-direct-preference-optimization" aria-label="Permalink to “DPO （Direct Preference Optimization）”">​</a></h3><p>直接偏好优化（DPO）是一种微调大型语言模型（LLM）以符合人类偏好的新颖方法。与涉及来自人类反馈的复杂强化学习 (RLHF) 的传统方法不同， DPO 简化了流程。它的工作原理是创建人类偏好对的数据集，每个偏好对都包含一个提示和两种可能的完成方式——一种是首选，一种是不受欢迎。然后对 LLM 进行微调，以最大限度地提高生成首选完成的可能性，并最大限度地减少生成不受欢迎的完成的可能性。 与 RLHF 相比， DPO 具有多项优势：</p><ul><li>简单性： DPO 更容易实施和训练，使其更易于使用。</li><li>稳定性：不易陷入局部最优，保证训练过程更加可靠。</li><li>效率：与 RLHF 相比， DPO 需要更少的计算资源和数据，使其计算量轻。</li><li>有效性：实验结果表明， DPO 在情感控制、摘要和对话生成等任务中可以优于 RLHF。</li></ul><h2 id="rlhf-开源资源" tabindex="-1">RLHF 开源资源 <a class="header-anchor" href="#rlhf-开源资源" aria-label="Permalink to “RLHF 开源资源”">​</a></h2><h3 id="开源-rlhf-算法库" tabindex="-1">开源 RLHF 算法库 <a class="header-anchor" href="#开源-rlhf-算法库" aria-label="Permalink to “开源 RLHF 算法库”">​</a></h3><h4 id="chatlearn" tabindex="-1">ChatLearn <a class="header-anchor" href="#chatlearn" aria-label="Permalink to “ChatLearn”">​</a></h4><p>Github: <a href="https://github.com/alibaba/ChatLearn" target="_blank" rel="noreferrer">https://github.com/alibaba/ChatLearn</a></p><p>ChatLearn 是阿里云 PAI 团队开发的大规模 Alignment 训练框架。ChatLearn 通过对模型计算逻辑的抽象，解耦了模型和计算 backend、分布式策略的绑定，提供灵活的资源调度机制，可以支持灵活的资源分配和并行调度策略。</p><p>ChatLearn 的特点如下：</p><ol><li><strong>易用的编程接口</strong>: ChatLearn 提供通用的编程抽象，用户只需要封装几个函数即可完成模型构造。用户只需要专注于单模型的编程，系统负责资源调度、数据流传输、控制流传输、分布式执行等。</li><li><strong>高可扩展的训练方式</strong>: ChatLearn 提供 RLHF、DPO、OnlineDPO、GRPO 等 Alignment 训练，同时也支持用户自定义 model 的执行 flow，使定制化训练流程变得非常便捷。</li><li><strong>多种分布式加速引擎</strong>: 用户可以使用不同的计算 backend 进行模型建模，如 Megatron-LM、DeepSpeed、vLLM 等。用户也可以组合使用不同的 backend，如用 Megatron-LM 来进行加速训练，用 vLLM 来加速推理。</li><li><strong>灵活的并行策略和资源分配</strong>: ChatLearn 支持不同模型配置不同的并行策略，可以结合各模型计算、显存、通信的特点来制定不同的并行策略。同时 ChatLearn 支持灵活的资源调度机制，支持各模型的资源独占或复用，通过系统调度策略支持高效的串行/并行执行和高效的显存共享。</li><li><strong>高性能</strong>: 相较于当前的 SOTA 系统， ChatLearn 在 7B+7B (Policy+Reward) 规模性能提升 52% ， 70B+70B 规模性能提升 137% 。同时， ChatLearn 支持更大规模的 Alignment 训练，例如： 300B+300B。</li></ol><h4 id="rlhflow" tabindex="-1">RLHFlow <a class="header-anchor" href="#rlhflow" aria-label="Permalink to “RLHFlow”">​</a></h4><p>Tech Report: <a href="https://arxiv.org/abs/2405.07863" target="_blank" rel="noreferrer"><strong>RLHF Workflow: From Reward Modeling to Online RLHF</strong></a></p><p>Code for Reward Modeling: <a href="https://github.com/RLHFlow/RLHF-Reward-Modeling" target="_blank" rel="noreferrer">https://github.com/RLHFlow/RLHF-Reward-Modeling</a></p><p>Code for Online RLHF: <a href="https://github.com/RLHFlow/Online-RLHF" target="_blank" rel="noreferrer">https://github.com/RLHFlow/Online-RLHF</a></p><p>Blog: <a href="https://rlhflow.github.io/" target="_blank" rel="noreferrer">https://rlhflow.github.io/</a></p><p>RLHFlow 提供了完整的在线迭代 RLHF 全流程解决方案，包括有监督学习、奖励函数建模及基于 DPO 的迭代 RLHF.</p><p>RLHFlow 的特点在于：</p><ol><li><strong>全流程开源</strong>： RLHFlow 不仅提供了完整的 RLHF 训练流程，包括有监督学习、奖励函数与偏好函数的建模，以及基于<a href="https://qianfan.cloud.baidu.com/" target="_blank" rel="noreferrer">DPO</a>的迭代 RLHF，还将模型、代码、数据及超参数选择全部开源到 GitHub 与 Hugging Face，供社区人员复现和进一步研究。</li><li><strong>在线迭代优势</strong>：与传统的离线 DPO 方法相比， RLHFlow 采用的在线迭代 RLHF 算法在性能上通常要明显更优。它不完全依赖于外部专家模型的回复，而是通过当前模型自己生成的回复组成的偏好数据集进行学习，从而更加高效地提升模型性能。</li><li><strong>先进性与可复现性</strong>：基于 LLaMA3-8B 模型， RLHFlow 实现了当前最先进的开源 RLHF 模型。同时，由于全流程的开源，社区人员可以轻松地复现这一结果，并在此基础上进行进一步的探索和优化。</li></ol><h4 id="openrlhf" tabindex="-1">OpenRLHF <a class="header-anchor" href="#openrlhf" aria-label="Permalink to “OpenRLHF”">​</a></h4><p>OpenRLHF 是一个基于 Ray、DeepSpeed 和 HF Transformers 构建的高性能 RLHF 框架：</p><ul><li>简单易用： OpenRLHF 是目前可用的最简单的高性能 RLHF 库之一，兼容 Huggingface 模型和数据集。</li><li>高性能： RLHF 训练的 80% 时间花费在样本生成阶段。得益于使用 Ray 和 Adam Offload （固定内存）可以使用大批量推理，使用 13B LLaMA2 模型的 OpenRLHF 性能是 DeepSpeedChat 的 4 倍。我们还支持 vLLM 生成加速以进一步提高生成性能。</li><li>分布式 RLHF: OpenRLHF 使用 Ray 将 Actor、Reward、Reference 和 Critic 模型分布到不同的 GPU 上，同时将 Adam 优化器放在 CPU 上。这使得使用多个 A100 80G GPU 和 vLLM 可以全面微调超过 70B+ 的模型 (见 <a href="https://github.com/OpenLLMAI/OpenRLHF/blob/main/docs/ray_architecture.png" target="_blank" rel="noreferrer">architecture</a>) 以及在多个 24GB RTX 4090 GPU 上微调 7B 模型。</li></ul><h4 id="trl" tabindex="-1">TRL <a class="header-anchor" href="#trl" aria-label="Permalink to “TRL”">​</a></h4><p>Github： <a href="https://github.com/huggingface/trl" target="_blank" rel="noreferrer">https://github.com/huggingface/trl</a></p><p><code>trl</code>库是一个全栈工具，可使用监督微调步骤 (SFT)、奖励建模 (RM) 和近端策略优化 (PPO) 以及直接偏好优化(DPO)等方法来微调和对齐 Transformer 语言和扩散模型。这是一个基于 Hugging Face 的 transformers 库的强化学习库，可以用于训练 Transformer 语言模型。</p><h4 id="trlx" tabindex="-1">TRLX <a class="header-anchor" href="#trlx" aria-label="Permalink to “TRLX”">​</a></h4><p>Github: <a href="https://github.com/CarperAI/trlx" target="_blank" rel="noreferrer">https://github.com/CarperAI/trlx</a></p><p>特点：</p><ul><li><p>最大支持 330 亿 参数的模型训练</p></li><li><p>支持两种强化学习算法： <a href="https://openai.com/research/openai-baselines-ppo" target="_blank" rel="noreferrer">近端策略优化 (PPO)</a>和[隐式语言 Q-学习 (ILQL)](<a href="https://docs.agilerl.com/en/latest/api/algorithms/ilql.html#:~:text=Implicit" target="_blank" rel="noreferrer">https://docs.agilerl.com/en/latest/api/algorithms/ilql.html#:~:text=Implicit</a> Language Q-Learning (ILQL) %23 ILQL is an,(LLMs) with reinforcement leaning from human feedback (RLHF).)。</p></li><li><p>TRLX 通过 Accelerate 支持的 Trainer 与 Hugging Face 模型无缝集成</p></li></ul><h4 id="rl4lm" tabindex="-1">RL4LM <a class="header-anchor" href="#rl4lm" aria-label="Permalink to “RL4LM”">​</a></h4><p>Github: <a href="https://github.com/allenai/RL4LMs" target="_blank" rel="noreferrer">https://github.com/allenai/RL4LMs</a></p><p>特点：</p><ul><li>OnPolicy 策略算法：实现了 PPO、A2C、TRPO 和 NLPO （自然语言策略优化）等策略算法。</li><li>支持因果 LM （例如 GPT-2/3）和 seq2seq LM （例如 T5、BART）的 Actor-Critic 策略。</li><li>基准测试： 通过 GRUE （General Reinforced-language Understanding Evaluation）基准测试，提供了一系列经过彻底测试和基准化的实验，涵盖了不同的 NLP 任务和奖励函数。 <ul><li>支持 7 种不同的自然语言处理（NLP）任务，包括摘要生成、生成常识推理、基于情感的文本续写、表格到文本生成、抽象问题回答、机器翻译和对话生成</li><li>提供 20 多种不同类型的 NLG 指标作为奖励函数，例如词汇指标（如 ROUGE、BLEU、SacreBLEU、METEOR）、语义指标（如 BERTSCORE、BLEURT）和特定任务指标（如 PARENT、CIDER、SPICE），来自预训练分类器的分数（例如：情绪分数）</li></ul></li><li>开源模块化库，可以方便的对接 Huggingface，模块可定制。</li></ul><h4 id="halos" tabindex="-1">HALOs <a class="header-anchor" href="#halos" aria-label="Permalink to “HALOs”">​</a></h4><p>Github： <a href="https://github.com/ContextualAI/HALOs" target="_blank" rel="noreferrer">https://github.com/ContextualAI/HALOs</a></p><p>该库很方便设计新的<strong>人类感知损失函数 (HALO)</strong>，以将 LLM 与大规模离线人类反馈保持一致（请阅读我们的<a href="https://github.com/ContextualAI/HALOs/blob/main/assets/report.pdf" target="_blank" rel="noreferrer">技术报告</a>或<a href="https://arxiv.org/abs/2402.01306" target="_blank" rel="noreferrer">全文</a>）。</p><p>该存储库借鉴了编写出色的<a href="https://github.com/eric-mitchell/direct-preference-optimization" target="_blank" rel="noreferrer">DPO 存储库</a>，并保留了原始版本的许多设计选择。我们引入的一些关键更改是：</p><ul><li>使数据加载更加模块化，以便您可以轻松编写自己的数据加载器</li><li>使训练器更加模块化，以便每个模块都有自己的训练器子类</li><li>添加以 GPT-4 作为法官进行开放式评估的代码</li><li>支持不止 SFT 和 DPO 的损失（包括 KTO、PPO (offline, off-policy variant) 和 SLiC）</li></ul><h4 id="deepspeed-chat" tabindex="-1">DeepSpeed Chat <a class="header-anchor" href="#deepspeed-chat" aria-label="Permalink to “DeepSpeed Chat”">​</a></h4><p>Github: <a href="https://github.com/microsoft/DeepSpeed/tree/master/blogs/deepspeed-chat" target="_blank" rel="noreferrer">https://github.com/microsoft/DeepSpeed/tree/master/blogs/deepspeed-chat</a></p><p>代码实现相对简洁，可以很方便的修改实现自己的想法。</p><h3 id="开源-rlhf-模型" tabindex="-1">开源 RLHF 模型 <a class="header-anchor" href="#开源-rlhf-模型" aria-label="Permalink to “开源 RLHF 模型”">​</a></h3><ul><li><a href="https://huggingface.co/HuggingFaceH4/zephyr-7b-beta" target="_blank" rel="noreferrer">Zephyr</a> 是推动 DPO 和普遍有用的 RLHF 模型激增的模型。</li><li><a href="https://arxiv.org/abs/2307.09288" target="_blank" rel="noreferrer">Llama 2</a> 在其论文中提供了大量的 RLHF 实现细节。</li></ul><h3 id="开源数据集" tabindex="-1">开源数据集 <a class="header-anchor" href="#开源数据集" aria-label="Permalink to “开源数据集”">​</a></h3><ul><li><a href="https://arxiv.org/abs/2310.01377" target="_blank" rel="noreferrer">UltraFeedback</a>：提供了训练 Zephyr 模型数据集。</li><li><a href="https://huggingface.co/datasets/OpenAssistant/oasst1" target="_blank" rel="noreferrer">Open Assistant 1</a>：社区生成的指导数据。</li><li><a href="https://huggingface.co/datasets/tatsu-lab/alpaca" target="_blank" rel="noreferrer">Alpaca</a>：第一个流行的合成指令数据，使用 ChatGPT 生成。</li><li><a href="https://sharegpt.com/" target="_blank" rel="noreferrer">ShareGPT</a> ：人们用来尝试在开放数据中获得类似 ChatGPT 的功能的大型数据集。</li></ul><h3 id="如何评价" tabindex="-1">如何评价 <a class="header-anchor" href="#如何评价" aria-label="Permalink to “如何评价”">​</a></h3><p>这三个评估是 RLHF 模型相对排名的综合集合。</p><ul><li><a href="https://chat.lmsys.org/" target="_blank" rel="noreferrer">ChatBotArena</a>：众包比较网站，是开放模型和封闭模型的模型质量的首选来源。</li><li><a href="https://huggingface.co/spaces/lmsys/chatbot-arena-leaderboard" target="_blank" rel="noreferrer">MT Bench</a>：同样由 LMSYS 构建的两回合聊天评估，与大多数 LLM 的实际评估非常相关。</li><li><a href="https://github.com/tatsu-lab/alpaca_eval" target="_blank" rel="noreferrer">AlpacaEval</a>：第一个以 GPT-4 作为法官的工具，用于推广 LLM 作为法官的实践。</li></ul><h2 id="rlhf-vs-sft" tabindex="-1">RLHF vs SFT <a class="header-anchor" href="#rlhf-vs-sft" aria-label="Permalink to “RLHF vs SFT”">​</a></h2><h3 id="rlhf-优点" tabindex="-1">RLHF 优点 <a class="header-anchor" href="#rlhf-优点" aria-label="Permalink to “RLHF 优点”">​</a></h3><p>RLHF 微调的效果可以概括为以下几点：</p><ol><li><strong>提高一致性</strong>：模型在不同情境下生成的文本更加一致，减少了随机性。</li><li><strong>增强质量</strong>：通过优先考虑人类偏好的响应，模型生成的文本质量得到提升。</li><li><strong>减少不适当内容</strong>：模型更能够识别并避免生成可能被认为是不适当或冒犯的内容。</li><li><strong>更好的对齐人类价值观</strong>：模型的响应更符合人类的道德、文化和社会价值观。</li><li><strong>提升用户满意度</strong>：最终，这些改进可以导致用户对模型的输出更加满意，因为它们更有可能符合用户的期望和偏好。</li></ol><h3 id="rlhf-的局限性" tabindex="-1">RLHF 的局限性 <a class="header-anchor" href="#rlhf-的局限性" aria-label="Permalink to “RLHF 的局限性”">​</a></h3><p>尽管 RLHF 模型在训练 AI 代理执行从机器人、视频游戏到 NLP 等复杂任务方面取得了令人印象深刻的成果，但使用 RLHF 并非没有局限性。</p><ul><li><p>人类偏好数据成本高昂。收集第一手人类反馈的需求可能会造成一个代价高昂的瓶颈，限制 RLHF 流程的可扩展性。Anthropic 和 Google 都提出了 AI 反馈强化学习 (RLAIF) 的方法，即让另一个 LLM 评估模型响应来取代部分或全部人类反馈，其结果与 RLHF 相当。</p></li><li><p>人类的输入具有高度主观性。要就“高质量”的输出到底是什么达成坚定的共识，几乎是不可能的，因为人类评估者不仅会对所谓的“事实”产生不同的意见，还会对“适当的”模型行为究竟应该如何理解存在分歧。因此，人类的分歧使得据以判断模型性能的“标准答案”无法形成。</p></li><li><p>人类评估者可能会犯错，甚至故意采取对抗性和恶意行为。人类对模型的引导并不总是出于善意，他们可能怀抱着真诚的反对意见，也可能故意操纵学习过程。Wolf 等人在 2016 年的一篇论文中提出，有毒行为应被视为人机交互中的一个基本预期，并建议需要一种方法来评估人类输入的可信度。2022 年， Meta AI 发布了<a href="https://arxiv.org/pdf/2208.03295.pdf" target="_blank" rel="noreferrer">一篇关于对抗性人类输入的论文</a>，研究了使用自动化方法“从高质量数据中获得最大学习效率，同时对低质量和对抗性数据具有最大稳健性”。该论文对各种“操纵”行为进行了分类，并确定了它们扭曲反馈数据的不同方式。</p></li><li><p>RLHF 存在过度拟合和偏见的风险。如果收集到的反馈来自一个非常有限的群体，那么当模型被其他群体使用，或者被用来处理与评估者持有某些偏见相关的主题时，可能会出现性能问题。</p></li></ul><h3 id="rlhf-vs-sft-1" tabindex="-1">RLHF vs SFT <a class="header-anchor" href="#rlhf-vs-sft-1" aria-label="Permalink to “RLHF vs SFT”">​</a></h3><ol><li>监督学习与强化学习的区别： <ul><li>在监督学习中，模型通过观察人类编写的文本和期望的输出来学习如何回答问题或执行任务，适用于文本基础任务。</li><li>在强化学习中，模型生成自己的答案，然后根据评分机制（如人类）的反馈来学习如何得到高分，适用于知识寻求和创造性任务。</li></ul></li><li>强化学习的挑战： <ul><li>强化学习比监督学习更难，因为它需要解决“信用分配”问题，即如何将最终得分反馈到生成的每个步骤。</li><li>强化学习需要一个评分机制，而在语言任务中，自动评分器很难实现，通常需要人类反馈。</li></ul></li><li>多样性论点： <ul><li>监督学习可能导致模型复制特定的答案，而人类语言中通常有多种方式传达相同信息。RL 训练可以提供更多的多样性。</li></ul></li><li>理论论点： <ul><li>监督学习只提供正面反馈，而强化学习允许负面反馈，这在理论上更强大，因为它允许模型形成自己的假设并从教师(Reward Model)那里获得反馈。</li></ul></li><li>核心论点： <ul><li>对于知识寻求型查询，强化学习是必要的，因为监督学习可能会教会模型撒谎。RL 训练不鼓励模型撒谎，即使模型最初猜测了一些正确答案，长期来看，它也会因为编造的答案（可能是错误的）而得到低分，并学会依赖其内部知识回答问题或选择不回答。</li></ul></li><li>教学模型放弃： <ul><li>在模型不知道答案的情况下，我们希望它能放弃并回答“我不知道”。这在监督学习中很难实现，而 RL 提供了一种可能的解决方案。</li></ul></li><li>模型窃取/蒸馏的影响： <ul><li>其他模型可能会尝试其他模型的行为，但这种方法可能不适用于知识寻求型查询，因为它可能会导致模型编造事实。</li></ul></li><li>无需人类反馈的 RL： <ul><li>尽管 RL 训练通常需要人类反馈，但使用大型预训练语言模型作为自动评分器， RL 训练变得更加实用。</li></ul></li></ol><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to “Reference”">​</a></h2><ul><li><a href="https://arxiv.org/abs/1909.08593" target="_blank" rel="noreferrer">Fine-Tuning Language Models from Human Preferences</a> (Zieglar et al. 2019): An early paper that studies the impact of reward learning on four specific tasks.</li><li><a href="https://proceedings.neurips.cc/paper/2020/hash/1f89885d556929e98d3ef9b86448f951-Abstract.html" target="_blank" rel="noreferrer">Learning to summarize with human feedback</a> (Stiennon et al., 2020): RLHF applied to the task of summarizing text. Also, <a href="https://arxiv.org/abs/2109.10862" target="_blank" rel="noreferrer">Recursively Summarizing Books with Human Feedback</a> (OpenAI Alignment Team 2021), follow on work summarizing books.</li><li><a href="https://arxiv.org/abs/2112.09332" target="_blank" rel="noreferrer">WebGPT: Browser-assisted question-answering with human feedback</a> (OpenAI, 2021): Using RLHF to train an agent to navigate the web.</li><li>InstructGPT: <a href="https://arxiv.org/abs/2203.02155" target="_blank" rel="noreferrer">Training language models to follow instructions with human feedback</a> (OpenAI Alignment Team 2022): RLHF applied to a general language model [<a href="https://openai.com/blog/instruction-following/" target="_blank" rel="noreferrer">Blog post</a> on InstructGPT].</li><li>GopherCite: <a href="https://www.deepmind.com/publications/gophercite-teaching-language-models-to-support-answers-with-verified-quotes" target="_blank" rel="noreferrer">Teaching language models to support answers with verified quotes</a> (Menick et al. 2022): Train a LM with RLHF to return answers with specific citations.</li><li>Sparrow: <a href="https://arxiv.org/abs/2209.14375" target="_blank" rel="noreferrer">Improving alignment of dialogue agents via targeted human judgements</a> (Glaese et al. 2022): Fine-tuning a dialogue agent with RLHF</li><li><a href="https://openai.com/blog/chatgpt/" target="_blank" rel="noreferrer">ChatGPT: Optimizing Language Models for Dialogue</a> (OpenAI 2022): Training a LM with RLHF for suitable use as an all-purpose chat bot.</li><li><a href="https://arxiv.org/abs/2210.10760" target="_blank" rel="noreferrer">Scaling Laws for Reward Model Overoptimization</a> (Gao et al. 2022): studies the scaling properties of the learned preference model in RLHF.</li><li><a href="https://arxiv.org/abs/2204.05862" target="_blank" rel="noreferrer">Training a Helpful and Harmless Assistant with Reinforcement Learning from Human Feedback</a> (Anthropic, 2022): A detailed documentation of training a LM assistant with RLHF.</li><li><a href="https://arxiv.org/abs/2209.07858" target="_blank" rel="noreferrer">Red Teaming Language Models to Reduce Harms: Methods, Scaling Behaviors, and Lessons Learned</a> (Ganguli et al. 2022): A detailed documentation of efforts to “discover, measure, and attempt to reduce [language models] potentially harmful outputs.”</li><li><a href="https://arxiv.org/abs/2208.02294" target="_blank" rel="noreferrer">Dynamic Planning in Open-Ended Dialogue using Reinforcement Learning</a> (Cohen at al. 2022): Using RL to enhance the conversational skill of an open-ended dialogue agent.</li><li><a href="https://arxiv.org/abs/2210.01241" target="_blank" rel="noreferrer">Is Reinforcement Learning (Not) for Natural Language Processing?: Benchmarks, Baselines, and Building Blocks for Natural Language Policy Optimization</a> (Ramamurthy and Ammanabrolu et al. 2022): Discusses the design space of open-source tools in RLHF and proposes a new algorithm NLPO (Natural Language Policy Optimization) as an alternative to PPO.</li><li><a href="https://arxiv.org/abs/2307.09288" target="_blank" rel="noreferrer">Llama 2</a> (Touvron et al. 2023): Impactful open-access model with substantial RLHF details.</li></ul>',68)])])}const L=r(o,[["render",h]]);export{u as __pageData,L as default};
